fn isqrt(n: i64) -> i64 = {
    if n == 0 { 0 } else {
        let mut lo: i64 = 0;
        let mut hi: i64 = 1000000000;
        while lo < hi {
            let mid: i64 = (lo + hi + 1) / 2;
            if mid * mid <= n { set lo = mid } else { set hi = mid - 1 }
        };
        lo
    }
};

